import {
    Box, Button, Paper, Table, TableBody, TableCell, TableContainer, TableHead, TableRow, TextField, Typography
  } from '@mui/material';
  import { Routes, Route, NavLink, Link, useParams, Outlet }
  from "react-router-dom";
  //import './App.css';
  import React, { useState, useEffect } from 'react';


function SearchPet(){
    const [isLoaded, setIsLoaded] = useState(false);
    const [pets, setPets] = useState([]);
    const [searchResults, setSearchResults] = useState([]);
    const [search, setSearch] = useState('');


        // fetches all pet data from the server
        function fetchPets()
        {
          fetch("http://localhost:3001/api?act=getall")
          .then(res => res.json())
          .then(
            (result) => {
              setIsLoaded(true);
              setPets(result);
            })    
        }

    useEffect(() => {
        fetch('/pets')
        .then(response => response.json())
        .then(data => {
            setPets(data);
            setSearchResults(data);
            setIsLoaded(true);
        });
    }, []);

    const handleSearch = (event) => {
        setSearch(event.target.value);
        const results = pets.filter(pet => pet.animal.toLowerCase().includes(event.target.value.toLowerCase()));
        setSearchResults(results);
    };

    return (
        <div>
            <h1>Search</h1>
            <p>Welcome to the Pet Store</p>
            <p>Here, you will be able to search for any of the pets within the table below</p>
            <TextField
                id="search"
                label="Search"
                variant="outlined"
                value={search}
                onChange={handleSearch}
            />
            <TableContainer component={Paper}>
                <Table>
                    <TableHead>
                        <TableRow>
                            <TableCell>Animal</TableCell>
                            <TableCell>Description</TableCell>
                            <TableCell>Age</TableCell>
                            <TableCell>Price</TableCell>
                        </TableRow>
                    </TableHead>
                    <TableBody>
                        {searchResults.map(pet => (
                            <TableRow key={pet.id}>
                                <TableCell>{pet.animal}</TableCell>
                                <TableCell>{pet.description}</TableCell>
                                <TableCell>{pet.age}</TableCell>
                                <TableCell>{pet.price}</TableCell>
                            </TableRow>
                        ))}
                    </TableBody>
                </Table>
            </TableContainer>
        </div>
    );

}




function Search() {
    return (
        <div>
        <h1>Search</h1>
        <p>Welcome to the Pet Store</p>
        <p>Here, you will be able to search for any of the pets within the table below</p>
        <SearchPet/>
        </div>
    );
}
export default Search;
